#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
const int N=502;int dp[N][N][N],n,M;
inline void UP(int &x){x<0?x+=M:0;}
int main()
{
	scanf("%d%d",&n,&M);
	rep(1,n-1,i)dp[1][1][i]=i;
	rep(1,n-1,i)
	{
		rep(1,i,j)rep(1,n-i,k)
		{
			dp[i+1][j+1][k]=(1ll*dp[i][j][k]*j%M*k+dp[i+1][j+1][k])%M;
			dp[i+1][j][k-1]=(1ll*dp[i][j][k]*j%M*(k-1)%M+dp[i+1][j][k-1])%M;
			UP(dp[i+1][j][k]-=2ll*dp[i][j][k]*j%M*k%M);
		}
	}
	rep(1,n-1,i)
	{
		int ans=0;rep(1,i,j)ans=(1ll*dp[i][j][1]*j+ans)%M;
		printf("%d\n",ans);
	}
}
